<template>
  <div :class="[currentLabel ? 'displayRow' : 'displayColumn', 'menuWrapper']">
    <IconSvg
      class="restore-menu"
      :path="ArrowLeft"
      v-if="currentLabel"
      :iconColorHover="'var(--primary)'"
      @click="handleClick('', $event)"
    />
    <div
      v-for="entry in props.list"
      :key="entry.name"
      class="label"
      @mouseover="hoverIndex = entry.name"
      @mouseleave="hoverIndex = null"
      @click="handleClick(entry.name, $event)"
    >
      <div class="label-content">
        <IconSvg
          :path="entry.icon"
          :iconColor="
            hoverIndex === entry.name ||
            (currentLabel === entry.name && !hoverIndex)
              ? 'var(--primary)'
              : 'var(--white)'
          "
        />
        <span class="panelTitle" v-if="!currentLabel">{{ entry.name }}</span>
      </div>
    </div>
  </div>
  <div class="subtitle" v-if="currentLabel">
    {{ hoverIndex || currentLabel }}
  </div>
</template>
<script lang="ts">
export interface PanelMenu {
  name: string;
  icon: string;
}
const menuEntries = ref<PanelMenu[]>([]);

export function sideBarMenuListOption() {
  return {
    menuEntries,
  };
}
</script>
<script setup lang="ts">
import IconSvg from "@/DesignSystem/Icons/IconSvg.vue";
import ArrowLeft from "@/DesignSystem/Icons/List/ArrowLeft";
import { ref, type PropType } from "vue";
const props = defineProps({
  /**
   * an array of Object with path icon and label to display
   */
  list: Array as PropType<PanelMenu[]>,
  /**
   * a callback function, get string label of current menu
   */
  onInteraction: {
    type: Function,
    required: false,
  },
});
const hoverIndex = ref<null | string>(null);
const currentLabel = ref<null | string>(null);

const handleClick = (value: string | null, event: Event) => {
  event.preventDefault();
  currentLabel.value = value;
  if (props.onInteraction) {
    props.onInteraction(currentLabel);
  }
};
</script>

